ain] DEBUG org.apache.http.impl.conn.DefaultManagedHttpClientConnection -- http-outgoing-3: Close connection 05:03:35.343 [main] DEBUG org.apache.http.impl.execchain.MainClientExec -- Connection discarded 05:03:35.343 [main] DEBUG org.apache.http.impl.conn.PoolingHttpClientConnectionManager -- Connection released: [id: 3][route: {s}->https://api.practicesoftwaretesting.com:443][total available: 0; route allocated: 0 of 5; total allocated: 0 of 10] 05:03:35.343 [main] DEBUG org.apache.http.impl.conn.PoolingHttpClientConnectionManager -- Connection manager is shutting down 05:03:35.343 [main] DEBUG org.apache.http.impl.conn.PoolingHttpClientConnectionManager -- Connection manager shut down 05:03:35.343 [main] DEBUG com.intuit.karate -- response time in milliseconds: 1268 1 < 200 1 < Date: Fri, 26 Jun 2026 09:03:57 GMT 1 < Server: Apache/2.4.52 (Ubuntu) 1 < Cache-Control: max-age=120, public 1 < Access-Control-Allow-Origin: * 1 < Access-Control-Expose-Headers: Content-Disposition 1 < Upgrade: h2 1 < Connection: Upgrade, close 1 < ETag: "2a623dedf914a4bd8cd88e1794f54f34-gzip" 1 < Vary: Accept-Encoding 1 < Content-Type: application/json {"current_page":1,"data":[{"id":"01KW1JH79B5GNP93PG4KMXNA22","name":"Combination Pliers","description":"Versatile combination pliers designed for gripping, bending, and cutting wire with ease. Featuring chrome vanadium steel construction with induction-hardened cutting edges, these pliers deliver excellent grip and leverage for a wide range of tasks. The precision-machined jaws combine flat gripping surfaces with a pipe-grip section and integrated wire cutter for true multi-purpose functionality. Ergonomic bi-component handles reduce hand fatigue during extended use and provide a secure hold even with oily or gloved hands. The joint is precisely fitted to eliminate play and ensure smooth operation over thousands of cycles. Ideal for electricians, mechanics, and DIY enthusiasts tackling everyday projects around the workshop or job site.","price":14.15,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBD","by_name":"Helinton Fantin","by_url":"https://unsplash.com/@fantin","source_name":"Unsplash","source_url":"https://unsplash.com/photos/W8BNwvOvW4M","file_name":"pliers01.avif","title":"Combination pliers"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SR","name":"Pliers","slug":"pliers"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K1","name":"ForgeFlex Tools"}},{"id":"01KW1JH79FP2SEMH9FBQWPG5X2","name":"Pliers","description":"Reliable general-purpose pliers crafted from drop-forged carbon steel for long-lasting durability in demanding working conditions. The serrated jaws provide a firm grip on a variety of materials including wire, nails, small fasteners, and irregularly shaped objects. Comfortable rubber-coated handles absorb vibration and reduce hand fatigue during extended use, while the non-slip surface ensures confident handling. The precision pivot joint maintains alignment under load, delivering smooth, controlled jaw action with every squeeze. Heat-treated steel construction resists wear and deformation even under heavy use. A must-have foundational tool for any workshop, equally suited for professional tradespeople and home repair projects.","price":12.01,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBE","by_name":"Everyday basics","by_url":"https://unsplash.com/@zanardi","source_name":"Unsplash","source_url":"https://unsplash.com/photos/I8eTuMmxIfo","file_name":"pliers02.avif","title":"Pliers"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SR","name":"Pliers","slug":"pliers"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K1","name":"ForgeFlex Tools"}},{"id":"01KW1JH79JG2CMFVEEPXN11PQR","name":"Bolt Cutters","description":"Heavy-duty bolt cutters engineered to slice through hardened bolts, chains, padlocks, and wire fencing with minimal effort. The compound leverage mechanism multiplies your cutting force by a factor of 30, enabling clean cuts through materials up to 10mm in diameter. Hardened alloy steel blades are precisely ground and heat-treated to maintain a sharp edge through years of repeated use on tough materials. Ergonomic rubber grips and the generous 750mm handle length provide excellent control, leverage, and reach during overhead or awkward-angle cuts. An adjustable blade tension screw lets you fine-tune the jaw alignment for optimal cutting performance. Built for demolition crews, locksmiths, fencing contractors, and maintenance professionals who need reliable cutting power day after day.","price":48.41,"is_location_offer":true,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBF","by_name":"Michael Dziedzic","by_url":"https://unsplash.com/@lazycreekimages","source_name":"Unsplash","source_url":"https://unsplash.com/photos/pM9pkc9J918","file_name":"pliers03.avif","title":"Bolt cutters"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SR","name":"Pliers","slug":"pliers"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K2","name":"MightyCraft Hardware"}},{"id":"01KW1JH79PSEP3HBQ13W4WVESE","name":"Long Nose Pliers","description":"Precision long nose pliers with narrow tapered jaws designed for reaching into tight, confined spaces and bending fine wire with accuracy. Made from chrome vanadium steel with induction-hardened cutting edges that cleanly sever copper, brass, and steel wire without crushing or fraying. The slim jaw profile tapers to a fine point, making these pliers indispensable for electrical terminal work, jewelry making, and intricate mechanical repairs. Bi-component comfort grips minimize hand strain during detailed tasks requiring a steady hand and controlled pressure. The leaf-spring joint returns the handles to the open position automatically, speeding up repetitive tasks. A must-have precision tool trusted by electricians, electronics technicians, and hobbyists worldwide.","price":14.24,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":false,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBG","by_name":"Brett Jordan","by_url":"https://unsplash.com/@brett_jordan","source_name":"Unsplash","source_url":"https://unsplash.com/photos/GamuDTVm02g","file_name":"pliers04.avif","title":"Long nose pliers"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SR","name":"Pliers","slug":"pliers"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K2","name":"MightyCraft Hardware"}},{"id":"01KW1JH79RWB4TJTQ8635YT37Y","name":"Slip Joint Pliers","description":"Adjustable slip joint pliers that feature a two-position pivot mechanism for switching between regular and wide jaw openings to accommodate different fastener sizes. The PVC-coated handles offer a comfortable, non-slip grip while the precisely machined jaws securely grasp round, flat, and hexagonal objects without slipping. Constructed from durable drop-forged carbon steel that has been heat-treated to withstand heavy daily use in professional environments. The curved jaw section grips pipes and cylindrical objects, while the flat front surface handles nuts, bolts, and sheet materials. A wire cutter integrated near the pivot handles light cutting tasks without reaching for a separate tool. Perfect for plumbing, automotive, HVAC, and general maintenance work where a single versatile gripping tool saves time.","price":9.17,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBH","by_name":"Yasin Hasan","by_url":"https://unsplash.com/@yasin","source_name":"Unsplash","source_url":"https://unsplash.com/photos/dwlxTSpfKXg","file_name":"pliers05.avif","title":"Slip joint pliers"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SR","name":"Pliers","slug":"pliers"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K2","name":"MightyCraft Hardware"}},{"id":"01KW1JH79Y340YYWJAA3030MSB","name":"Claw Hammer with Shock Reduction Grip","description":"Ergonomic claw hammer featuring an advanced shock reduction grip system that absorbs up to 70% of impact vibrations, protecting your wrist, elbow, and shoulder during prolonged nailing sessions. The 450g carbon steel head is precision-balanced and heat-treated for maximum hardness, ensuring accurate nail driving with minimal effort on every swing. The curved claw design effortlessly removes nails without damaging surrounding wood surfaces, making it equally useful for construction and renovation work. A fiberglass-reinforced handle combines lightweight strength with exceptional durability that far outlasts traditional wooden handles. The overmolded soft-grip zone conforms to your hand shape for a custom-feeling, fatigue-free hold throughout long working days. Recommended for professional framing, carpentry, and renovation projects where operator comfort matters as much as striking performance.","price":13.41,"is_location_offer":true,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBJ","by_name":"iMattSmart","by_url":"https://unsplash.com/@imattsmart","source_name":"Unsplash","source_url":"https://unsplash.com/photos/jaLaLQdkBOE","file_name":"hammer01.avif","title":"Claw Hammer"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SM","name":"Hammer","slug":"hammer"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K1","name":"ForgeFlex Tools"}},{"id":"01KW1JH7A0Q8S435YE8CPZN1BE","name":"Hammer","description":"A dependable standard claw hammer suitable for driving and removing nails in everyday construction, carpentry, and home improvement projects. The 350g carbon steel head is drop-forged and heat-treated for maximum hardness, then fitted to a traditional wooden handle that provides natural shock absorption with each strike. Well-balanced weight distribution between the head and handle ensures accurate strikes with minimal wrist effort, reducing fatigue during repetitive nailing tasks. The polished face resists rust and provides a smooth surface that drives nails cleanly without leaving marks on finish materials. A gently curved claw provides reliable nail extraction leverage without excessive force. This versatile hammer belongs in every toolbox, from professional carpentry workshops to home garages and apartment maintenance kits.","price":12.58,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBK","by_name":"Jozsef Hocza","by_url":"https://unsplash.com/@hocza","source_name":"Unsplash","source_url":"https://unsplash.com/photos/D3nouOYbALc","file_name":"hammer02.avif","title":"Hammer"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SM","name":"Hammer","slug":"hammer"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K1","name":"ForgeFlex Tools"}},{"id":"01KW1JH7A1RW6YQEZ9YW4QF8FA","name":"Claw Hammer","description":"Traditional claw hammer with a polished carbon steel head engineered for driving and removing nails with precision and confidence. The rubber-wrapped handle provides a secure, comfortable grip even in wet, dusty, or cold conditions where bare metal or wood handles would slip. At 500g, it offers the ideal balance between striking power and maneuverability for general carpentry, framing, and construction tasks. The curved claw design allows for smooth nail extraction without gouging or marring wood surfaces, protecting your finished work. The head-to-handle connection uses an epoxy-bonded wedge system that prevents loosening over time. A reliable, no-nonsense tool that professional carpenters and weekend builders alike reach for every day.","price":11.48,"is_location_offer":true,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBM","by_name":"Andrew George","by_url":"https://unsplash.com/@andrewjoegeorge","source_name":"Unsplash","source_url":"https://unsplash.com/photos/YU2mCvXR0wA","file_name":"hammer03.avif","title":"Claw Hammer"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SM","name":"Hammer","slug":"hammer"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K2","name":"MightyCraft Hardware"}},{"id":"01KW1JH7A3EJ638132WK9NF5Q7","name":"Thor Hammer","description":"The legendary Thor Hammer combines premium craftsmanship with raw striking power in a tool that is truly built to last generations. Forged from Uru metal with a hand-wrapped leather grip, this extraordinary 5kg masterpiece delivers unmatched impact force for the most demanding demolition, forging, and heavy construction tasks. The perfectly balanced oversized head ensures every swing transfers maximum energy to the target, while the enlarged striking face covers more surface area than any conventional hammer. Despite its impressive mass, the ergonomic handle design and precise weight distribution allow for surprisingly controlled, accurate swings. This is not merely a tool but a statement piece for those who accept nothing less than the absolute best in their workshop. Comes with a lifetime warranty because true legends never fade. Please note: only one Thor Hammer is permitted per customer.","price":11.14,"is_location_offer":false,"is_rental":false,"co2_rating":"D","in_stock":true,"is_eco_friendly":false,"product_image":{"id":"01KW1JH78RWS5VMECPR1798KBN","by_name":"ANIRUDH","by_url":"https://unsplash.com/@lanirudhreddy","source_name":"Unsplash","source_url":"https://unsplash.com/photos/3esjG-nlgyk","file_name":"hammer04.avif","title":"Hammer"},"category":{"id":"01KW1JH78EKAKY7TJGMPK8X8SM","name":"Hammer","slug":"hammer"},"brand":{"id":"01KW1JH6Y3JBZYDNB6A1NDC0K1","name":"ForgeFlex Tools"}}],"from":1,"last_page":6,"per_page":9,"to":9,"total":51}

